from flask import Flask, send_file, jsonify, g
import os
from io import BytesIO

app = Flask(__name__)

INVOICE_STORAGE_PATH = '/var/invoices'


def get_invoice_owner(invoice_id):
    invoice_owners = {
        1: 'user1',
        2: 'user1',
        3: 'user2',
        4: 'user3',
        5: 'user2',
    }
    return invoice_owners.get(invoice_id)


def get_invoice_path(invoice_id):
    return os.path.join(INVOICE_STORAGE_PATH, f'invoice_{invoice_id}.pdf')


@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    current_user = g.user
    
    invoice_owner = get_invoice_owner(invoice_id)
    
    if not invoice_owner:
        return jsonify({'error': 'Invoice not found'}), 404
    
    if invoice_owner != current_user:
        return jsonify({'error': 'Unauthorized access to this invoice'}), 403
    
    invoice_path = get_invoice_path(invoice_id)
    
    if not os.path.exists(invoice_path):
        return jsonify({'error': 'Invoice file not found'}), 404
    
    return send_file(
        invoice_path,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=f'invoice_{invoice_id}.pdf'
    )


